import{_ as e,o as a,c as r,a3 as l}from"./chunks/framework.BTFg6ESq.js";const f=JSON.parse('{"title":"🔣 宏系统 (Macro System) 概览","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/macro-system/index.md","filePath":"user-guide/tools/llm-chat/macro-system/index.md","lastUpdated":1778244893000}'),o={name:"user-guide/tools/llm-chat/macro-system/index.md"};function s(d,t,i,n,c,h){return a(),r("div",null,[...t[0]||(t[0]=[l('<div><h1 id="🔣-宏系统-macro-system-概览" tabindex="-1">🔣 宏系统 (Macro System) 概览 <a class="header-anchor" href="#🔣-宏系统-macro-system-概览" aria-label="Permalink to &quot;🔣 宏系统 (Macro System) 概览&quot;">​</a></h1><p>宏系统是 LLM Chat 中一个强大的动态内容生成引擎。它允许你在智能体的预设消息、用户输入、正则替换等任何支持文本的地方嵌入可执行的占位符，从而实现根据上下文动态调整提示词 (Prompt) 的能力。</p><h2 id="什么是宏" tabindex="-1">什么是宏？ <a class="header-anchor" href="#什么是宏" aria-label="Permalink to &quot;什么是宏？&quot;">​</a></h2><p>宏是一种用 <code>{{ }}</code> 包裹的特殊标记。在系统组装上下文并发送给 LLM 之前，这些标记会被自动展开为实际的内容（如当前时间、用户名、变量值等）。</p><h3 id="基础语法" tabindex="-1">基础语法 <a class="header-anchor" href="#基础语法" aria-label="Permalink to &quot;基础语法&quot;">​</a></h3><ul><li><strong>无参数宏</strong>: <code>{{macroName}}</code></li><li><strong>带参数宏</strong>: <code>{{macroName::arg1::arg2}}</code></li><li><strong>转义</strong>: 如果需要输出原文字符 <code>{{</code>，请使用 <code>\\{{text}}</code>。</li></ul><h2 id="执行机制-三阶段管道" tabindex="-1">执行机制：三阶段管道 <a class="header-anchor" href="#执行机制-三阶段管道" aria-label="Permalink to &quot;执行机制：三阶段管道&quot;">​</a></h2><p>为了保证宏之间的依赖关系被正确处理（例如：必须先“设置”变量，才能“读取”变量），宏引擎采用三阶段执行管道：</p><ol><li><strong>预处理 (PRE_PROCESS)</strong>: 处理状态变更宏（如 <code>setvar</code>, <code>incvar</code>）。这些宏通常执行逻辑操作，不返回可见文本。</li><li><strong>替换 (SUBSTITUTE)</strong>: 处理静态值替换（如 <code>{{user}}</code>, <code>{{getvar}}</code>）。</li><li><strong>后处理 (POST_PROCESS)</strong>: 执行依赖最终文本上下文或需要实时计算的函数（如 <code>{{time}}</code>, <code>{{lastMessage}}</code>, <code>{{cssvar}}</code>）。</li></ol><h2 id="核心功能分类" tabindex="-1">核心功能分类 <a class="header-anchor" href="#核心功能分类" aria-label="Permalink to &quot;核心功能分类&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">分类</th><th style="text-align:left;">说明</th><th style="text-align:left;">详细参考</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>核心上下文</strong></td><td style="text-align:left;">获取用户、Agent 名称及描述</td><td style="text-align:left;"><a href="./macro-reference#1-核心上下文宏">宏参考</a></td></tr><tr><td style="text-align:left;"><strong>时间与日期</strong></td><td style="text-align:left;">感知虚拟时间线，支持多种语言格式</td><td style="text-align:left;"><a href="./macro-reference#2-时间与日期宏">宏参考</a></td></tr><tr><td style="text-align:left;"><strong>变量操作</strong></td><td style="text-align:left;">在请求过程中传递和共享状态</td><td style="text-align:left;"><a href="./session-variables">会话变量</a></td></tr><tr><td style="text-align:left;"><strong>逻辑与功能</strong></td><td style="text-align:left;">随机选择、掷骰子、重复文本</td><td style="text-align:left;"><a href="./macro-reference#4-功能性宏">宏参考</a></td></tr><tr><td style="text-align:left;"><strong>资产与工具</strong></td><td style="text-align:left;">注入工具定义、资产列表及运行时上下文</td><td style="text-align:left;"><a href="./macro-reference#6-资产与工具宏">宏参考</a></td></tr></tbody></table><hr><h3 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h3><ul><li><a href="./macro-reference">完整宏参考手册</a></li><li><a href="./session-variables">会话变量系统详解</a></li><li><a href="./css-variables-guide">CSS 变量与视觉化输出</a></li></ul></div>',1)])])}const m=e(o,[["render",s]]);export{f as __pageData,m as default};
